import{_ as e,o as i,c as s,a4 as o}from"./chunks/framework.B4F_pDg-.js";const k=JSON.parse('{"title":"38解锁节","description":"","frontmatter":{},"headers":[],"relativePath":"docs/root/38bl.md","filePath":"docs/root/38bl.md"}'),t={name:"docs/root/38bl.md"};function l(d,a,c,r,n,h){return i(),s("div",null,[...a[0]||(a[0]=[o('<h1 id="_38解锁节" tabindex="-1">38解锁节 <a class="header-anchor" href="#_38解锁节" aria-label="Permalink to “38解锁节”">​</a></h1><p><em>最后编辑于2026/06/28 by:nood</em></p><blockquote><p>⚠警告: root后 你所作出的一些行为可能会导致手机系统损坏</p></blockquote><h2 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to “介绍”">​</a></h2><p>本文的内容大部分都来自<a href="https://www.coolapk.com/" target="_blank" rel="noreferrer">酷安</a> 临时root/免解root/解BL是因为小米17系列8e5芯片发现漏洞然后掀起的这场风波 在2026/03/08的事情 也叫做38解锁节</p><h2 id="机型" tabindex="-1">机型 <a class="header-anchor" href="#机型" aria-label="Permalink to “机型”">​</a></h2><p>临时root/免解root/绕社区解BL锁分机型和系统 只有部分机型和系统匹配的才可以 基本上都是骁龙处理器和小米手机</p><ul><li>Snapdragon 8 Elite Gen 5 <code>Android安全更新补丁2026-02-01</code>及以前</li><li>Snapdragon 8 Elite <code>Android安全更新补丁2026-01-01</code>及以前</li><li>Snapdragon Gen 3 <code>Android安全更新补丁2026-02-01</code>及以前</li><li>Snapdragon Gen 2 <code>Android安全更新补丁2026-01-01</code>及以前</li><li>Snapdragon Gen 1 <code>Android安全更新补丁2026-01-01</code>及以前</li></ul><h2 id="通用操作流程" tabindex="-1">通用操作流程 <a class="header-anchor" href="#通用操作流程" aria-label="Permalink to “通用操作流程”">​</a></h2><p>在手机上 需要打开<code>开发者设置</code>(在设置连点<code>系统版本号</code>就可以成功打开<code>开发者设置</code>了 从设置中搜索<code>开发者设置</code>就能找到了) 找到<code>USB调试</code> 将<code>USB调试</code>打开 如果有<code>USB安装</code>也要把<code>USB安装</code>打开 首先我们需要一根数据线 插到手机和电脑上 手机上这时会弹出来一个<code>USB调试</code>的权限申请 点击<code>始终允许通过此计算机调试</code>然后点击<code>允许</code></p><h2 id="临时root" tabindex="-1">临时root <a class="header-anchor" href="#临时root" aria-label="Permalink to “临时root”">​</a></h2><p>连接成功后 我们有以下几个选择</p><h3 id="方法1" tabindex="-1">方法1 <a class="header-anchor" href="#方法1" aria-label="Permalink to “方法1”">​</a></h3><p>我们需要去下载platform-tools 这个是谷歌官方的工具 包含了fastboot和adb命令 下载好以后放在电脑上的一个位置(是解压过的 并且里面有fastboot.exe和adb.exe) 并把整个文件夹添加到系统环境变量里面 然后打开cmd</p><h3 id="方法2" tabindex="-1">方法2 <a class="header-anchor" href="#方法2" aria-label="Permalink to “方法2”">​</a></h3><p>下载搞机助手 在扩展功能那里找到Cmd命令行并打开</p><p>方法1和方法2打开cmd以后 需要先将手机进入fastboot 也可以在cmd输入:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha" style="--shiki-light:#4c4f69;--shiki-dark:#cdd6f4;--shiki-light-bg:#eff1f5;--shiki-dark-bg:#1e1e2e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">adb</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> reboot</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> bootloader</span></span></code></pre></div><p>执行完成会显示一个<code>OK</code>的字样 进入fastboot后(一般都是背景黑色 有字的那种就是) 然后在cmd输入:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha" style="--shiki-light:#4c4f69;--shiki-dark:#cdd6f4;--shiki-light-bg:#eff1f5;--shiki-dark-bg:#1e1e2e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">fastboot</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> oem</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> set-gpu-preemption</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> 0</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> androidboot.selinux=permissive</span></span></code></pre></div><p>执行完成会显示一个<code>OK</code>的字样 然后我们进入系统 可以直接长按电源键重启 也可以在cmd输入:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha" style="--shiki-light:#4c4f69;--shiki-dark:#cdd6f4;--shiki-light-bg:#eff1f5;--shiki-dark-bg:#1e1e2e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;">fastboot</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> continue</span></span></code></pre></div><h3 id="方法3" tabindex="-1">方法3 <a class="header-anchor" href="#方法3" aria-label="Permalink to “方法3”">​</a></h3><p>找一个自动脚本双击.exe即可 会直接给你下载KernelSU 并且直接越狱</p><h2 id="解bl锁" tabindex="-1">解BL锁 <a class="header-anchor" href="#解bl锁" aria-label="Permalink to “解BL锁”">​</a></h2><p>你可以前往<a href="https://www.coolapk.com/feed/71419495?s=OGY3ZTcxZjQyN2M3OTEwZzZhNDEyZDE4ega1603" target="_blank" rel="noreferrer">酷安@莫离然然</a> 那里有更详细的教程</p>',26)])])}const b=e(t,[["render",l]]);export{k as __pageData,b as default};
